mapper.select:
SELECT s.sale_id AS id, s.customer_id, s.total_amount, s.total_cost, s.sale_date, (SELECT c.name FROM customers c WHERE c.id = s.customer_id) AS name, (SELECT c.gender FROM customers c WHERE c.id = s.customer_id) AS gender FROM sales s WHERE 1=1
AND s.customer_id = #{customerId}
AND s.sale_date BETWEEN #{startDate} AND #{endDate}
ORDER BY s.sale_date DESC

mapper.update:
UPDATE sale_items
SET quantity = #{quantity}, unit_price = #{unitPrice},
    subtotal = #{unitPrice} * #{quantity}
WHERE sale_id = #{saleId} AND book_id = #{bookId}
